// Requires NODE_FUNCTION_ALLOW_BUILTIN=crypto on the n8n host.
const crypto = require('crypto');

const headers = $json.headers || {};
const getHeader = (name) => {
  const key = Object.keys(headers).find((k) => k.toLowerCase() === name.toLowerCase());
  return key ? String(headers[key]) : '';
};

const timestamp = getHeader('x-slack-request-timestamp');
const slackSig = getHeader('x-slack-signature');
if (!timestamp || !slackSig) {
  throw new Error('Missing X-Slack-Request-Timestamp or X-Slack-Signature');
}

const ageMs = Math.abs(Date.now() - Number(timestamp) * 1000);
if (!Number.isFinite(ageMs) || ageMs > 5 * 60 * 1000) {
  throw new Error('Slack timestamp older than five minutes (or invalid)');
}

const rawBody =
  $json.rawBody ??
  $json.body?.rawBody ??
  (typeof $json.body === 'string' ? $json.body : null) ??
  ($binary?.data ? Buffer.from($binary.data.data ?? $binary.data, 'base64').toString('utf8') : null);

if (typeof rawBody !== 'string' || !rawBody.length) {
  throw new Error('Raw body missing — enable webhook rawBody retention');
}

const signingSecret = $env.SLACK_SIGNING_SECRET;
if (!signingSecret) throw new Error('SLACK_SIGNING_SECRET not set');

const base = `v0:${timestamp}:${rawBody}`;
const digest = crypto.createHmac('sha256', signingSecret).update(base, 'utf8').digest('hex');
const computed = `v0=${digest}`;

const a = Buffer.from(computed);
const b = Buffer.from(slackSig);
if (a.length !== b.length || !crypto.timingSafeEqual(a, b)) {
  throw new Error('Slack signature verification failed');
}

// Parse payload only AFTER HMAC + timestamp checks.
let form = {};
try {
  form = Object.fromEntries(new URLSearchParams(rawBody));
} catch {
  form = {};
}
const payloadRaw = form.payload || (typeof $json.body?.payload === 'string' ? $json.body.payload : null);
if (!payloadRaw) throw new Error('Slack payload missing after verify');
const payload = typeof payloadRaw === 'string' ? JSON.parse(payloadRaw) : payloadRaw;

const channelId = payload.channel?.id || payload.container?.channel_id;
const userId = payload.user?.id;
const allowedChannel = $env.SLACK_CLAY_LEADS_CHANNEL_ID;
const approvers = String($env.SLACK_CLAY_APPROVER_USER_IDS || '')
  .split(/[,\s]+/)
  .map((s) => s.trim())
  .filter(Boolean);

if (!channelId || channelId !== allowedChannel) {
  throw new Error('Interaction channel.id must equal SLACK_CLAY_LEADS_CHANNEL_ID');
}
if (!userId || !approvers.includes(userId)) {
  throw new Error('user.id not in SLACK_CLAY_APPROVER_USER_IDS');
}

const action = (payload.actions && payload.actions[0]) || null;
if (!action) throw new Error('No interactive action');
const actionId = action.action_id;
if (actionId !== 'clay_batch_approve' && actionId !== 'clay_batch_reject') {
  throw new Error(`Unsupported action_id: ${actionId}`);
}

let value = {};
try {
  value = typeof action.value === 'string' ? JSON.parse(action.value) : action.value || {};
} catch {
  value = {};
}
const batch_id = value.batch_id || payload.message?.metadata?.event_payload?.batch_id;
if (!batch_id) throw new Error('batch_id missing from action value');

return [{
  json: {
    ok: true,
    action_id: actionId,
    batch_id,
    user_id: userId,
    user_name: payload.user?.name || payload.user?.username || userId,
    channel_id: channelId,
    message_ts: payload.message?.ts || payload.container?.message_ts,
    original_blocks: payload.message?.blocks || [],
    response_url: payload.response_url,
    dashboard_link: (payload.message?.blocks || [])
      .map((b) => b?.text?.text || '')
      .find((t) => /Dashboard|Open Approval/i.test(t)) || null,
  },
}];

const verified = $('Verify HMAC Timestamp Channel User').item.json;
const api = $json;
const statusCode = api.statusCode ?? api.status ?? null;
const ok = api.ok === true || (statusCode >= 200 && statusCode < 300 && api.error == null);
const statusLabel = verified.action_id === 'clay_batch_approve' ? 'approved' : 'rejected';
const actor = verified.user_name || verified.user_id;

const reviewLink =
  verified.dashboard_link ||
  `Dashboard: /dashboard/marketing-agents?category=clay_leads&batch_id=${verified.batch_id}`;

let blocks;
if (ok) {
  blocks = [
    {
      type: 'section',
      text: {
        type: 'mrkdwn',
        text: `*Clay batch \`${verified.batch_id}\` ${statusLabel}* by <@${verified.user_id}> (${actor}).`,
      },
    },
    {
      type: 'section',
      text: { type: 'mrkdwn', text: reviewLink },
    },
  ];
} else {
  const errText = api.error || api.message || JSON.stringify(api).slice(0, 280);
  blocks = [
    {
      type: 'section',
      text: {
        type: 'mrkdwn',
        text: `*Clay batch \`${verified.batch_id}\` — retryable error* (actor <@${verified.user_id}> tried ${statusLabel}).\n\`${errText}\``,
      },
    },
    {
      type: 'section',
      text: { type: 'mrkdwn', text: `Keep review link and retry:\n${reviewLink}` },
    },
  ];
}

return [{
  json: {
    channel: verified.channel_id,
    ts: verified.message_ts,
    text: ok
      ? `Clay batch ${verified.batch_id} ${statusLabel} by ${actor}`
      : `Clay batch ${verified.batch_id} retryable error`,
    blocks,
    ok,
  },
}];
